CREATE TABLE workflow_definitions(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),organization_id uuid NOT NULL REFERENCES organizations(id),activity text NOT NULL,key text NOT NULL,name text NOT NULL,steps jsonb NOT NULL CHECK(jsonb_typeof(steps)='array'),active boolean NOT NULL DEFAULT true,version integer NOT NULL CHECK(version>=1),created_at timestamptz NOT NULL,UNIQUE(tenant_id,organization_id,key,version));
CREATE TABLE workflow_instances(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),organization_id uuid NOT NULL REFERENCES organizations(id),site_id uuid NOT NULL REFERENCES sites(id),definition_id uuid NOT NULL REFERENCES workflow_definitions(id),subject_type text NOT NULL,subject_id uuid NOT NULL,step_key text NOT NULL,status text NOT NULL CHECK(status IN('open','completed','cancelled')),priority text NOT NULL CHECK(priority IN('low','normal','high','urgent')),data jsonb NOT NULL DEFAULT '{}'::jsonb CHECK(jsonb_typeof(data)='object'),version integer NOT NULL CHECK(version>=1),started_at timestamptz NOT NULL,updated_at timestamptz NOT NULL,completed_at timestamptz);
CREATE INDEX workflow_instances_subject_idx ON workflow_instances(tenant_id,subject_type,subject_id);
CREATE TABLE workflow_work_items(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),instance_id uuid NOT NULL REFERENCES workflow_instances(id),step_key text NOT NULL,title text NOT NULL,assigned_to uuid,assigned_role text,priority text NOT NULL CHECK(priority IN('low','normal','high','urgent')),due_at timestamptz,status text NOT NULL CHECK(status IN('open','completed','cancelled')),created_at timestamptz NOT NULL,completed_at timestamptz);
CREATE INDEX workflow_work_items_queue_idx ON workflow_work_items(tenant_id,status,assigned_role,due_at) WHERE status='open';
CREATE UNIQUE INDEX workflow_one_open_item_idx ON workflow_work_items(tenant_id,instance_id) WHERE status='open';
DO $$ DECLARE n text;BEGIN FOREACH n IN ARRAY ARRAY['workflow_definitions','workflow_instances','workflow_work_items'] LOOP EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY',n);EXECUTE format('ALTER TABLE %I FORCE ROW LEVEL SECURITY',n);EXECUTE format('CREATE POLICY tenant_isolation ON %I USING (tenant_id=current_setting(''app.tenant_id'',true)::uuid) WITH CHECK (tenant_id=current_setting(''app.tenant_id'',true)::uuid)',n);END LOOP;END $$;
